import org.junit.jupiter.api.Test;
import static org.junit.jupiter.api.Assertions.*;

public class SolutionTest {
    @Test
    void middlePivot() {
        // left of i=3: 1+7+3=11. Right of i=3: 5+6=11.
        assertEquals(3, new Solution().pivotIndex(new int[]{1, 7, 3, 6, 5, 6}));
    }

    @Test
    void noPivot() {
        assertEquals(-1, new Solution().pivotIndex(new int[]{1, 2, 3}));
    }

    @Test
    void leftEdgePivot() {
        // left of i=0 = 0, right of i=0 = 1 + (-1) = 0
        assertEquals(0, new Solution().pivotIndex(new int[]{2, 1, -1}));
    }

    @Test
    void single() {
        assertEquals(0, new Solution().pivotIndex(new int[]{5}));
    }

    @Test
    void empty() {
        assertEquals(-1, new Solution().pivotIndex(new int[]{}));
    }
}
